from __future__ import annotations

from dataclasses import dataclass
from typing import Optional, Tuple

import numpy as np

try:
    import cv2  # type: ignore
except Exception:  # pragma: no cover
    cv2 = None

try:
    from PIL import Image
except Exception:  # pragma: no cover
    Image = None


Array = np.ndarray


@dataclass
class PreprocessResult:
    original: Array
    gray: Array
    coarse_image: Array
    background: Optional[Array]
    flattened: Array
    scale: float


class Preprocessor:
    def __init__(
        self,
        target_max_dim: int = 2048,
        gaussian_sigma: float = 1.2,
        blur_kernel: int = 5,
        background_kernel_ratio: float = 0.08,
        use_clahe: bool = True,
    ) -> None:
        self.target_max_dim = max(256, int(target_max_dim))
        self.gaussian_sigma = float(gaussian_sigma)
        self.blur_kernel = int(blur_kernel) if int(blur_kernel) % 2 == 1 else int(blur_kernel) + 1
        self.background_kernel_ratio = float(background_kernel_ratio)
        self.use_clahe = bool(use_clahe)

    def load_image(self, image_path: str) -> Array:
        if cv2 is not None:
            img = cv2.imread(image_path, cv2.IMREAD_UNCHANGED)
            if img is not None:
                if img.ndim == 3:
                    gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
                else:
                    gray = img
                return self._ensure_uint8(gray)

        if Image is None:
            raise FileNotFoundError(f"Unable to load image: {image_path}")

        with Image.open(image_path) as im:
            gray = im.convert("L")
            return np.asarray(gray, dtype=np.uint8)

    def preprocess(self, image: Array) -> PreprocessResult:
        gray = self._ensure_uint8(image)
        blurred = self.gaussian_blur(gray)
        flattened, background = self.subtract_background(blurred)
        normalized = self.normalize_contrast(flattened)
        coarse_image, scale = self.downsample(normalized)
        return PreprocessResult(
            original=gray,
            gray=gray,
            coarse_image=coarse_image,
            background=background,
            flattened=normalized,
            scale=scale,
        )

    def preprocess_path(self, image_path: str) -> PreprocessResult:
        return self.preprocess(self.load_image(image_path))

    def downsample(self, image: Array) -> Tuple[Array, float]:
        h, w = image.shape[:2]
        max_dim = max(h, w)
        if max_dim <= self.target_max_dim:
            return image.copy(), 1.0
        scale = self.target_max_dim / float(max_dim)
        new_w = max(1, int(round(w * scale)))
        new_h = max(1, int(round(h * scale)))
        if cv2 is not None:
            resized = cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_AREA)
        else:
            pil = Image.fromarray(image)
            resized = np.asarray(pil.resize((new_w, new_h), Image.Resampling.BILINEAR), dtype=np.uint8)
        return resized, scale

    def gaussian_blur(self, image: Array) -> Array:
        if cv2 is not None:
            return cv2.GaussianBlur(image, (self.blur_kernel, self.blur_kernel), self.gaussian_sigma)

        # fallback: separable 1D Gaussian approximation via convolution
        radius = self.blur_kernel // 2
        x = np.arange(-radius, radius + 1, dtype=np.float32)
        sigma = max(self.gaussian_sigma, 1e-6)
        kernel = np.exp(-(x ** 2) / (2 * sigma * sigma))
        kernel /= kernel.sum()
        temp = np.apply_along_axis(lambda m: np.convolve(m, kernel, mode="same"), axis=1, arr=image.astype(np.float32))
        out = np.apply_along_axis(lambda m: np.convolve(m, kernel, mode="same"), axis=0, arr=temp)
        return np.clip(out, 0, 255).astype(np.uint8)

    def subtract_background(self, image: Array) -> Tuple[Array, Optional[Array]]:
        h, w = image.shape[:2]
        kernel = max(15, int(round(max(h, w) * self.background_kernel_ratio)))
        if kernel % 2 == 0:
            kernel += 1

        if cv2 is not None:
            background = cv2.GaussianBlur(image, (kernel, kernel), 0)
            flat = cv2.addWeighted(image, 1.0, background, -1.0, 127)
            return self._ensure_uint8(flat), self._ensure_uint8(background)

        # NumPy fallback using heavy blur approximation by repeated box filters.
        bg = image.astype(np.float32)
        for _ in range(3):
            bg = self._box_blur(bg, max(7, kernel // 8))
        flat = image.astype(np.float32) - bg + 127.0
        return np.clip(flat, 0, 255).astype(np.uint8), np.clip(bg, 0, 255).astype(np.uint8)

    def normalize_contrast(self, image: Array) -> Array:
        if cv2 is not None and self.use_clahe:
            clahe = cv2.createCLAHE(clipLimit=2.0, tileGridSize=(8, 8))
            return clahe.apply(image)

        lo, hi = np.percentile(image, [1, 99])
        if hi <= lo:
            return image.copy()
        out = (image.astype(np.float32) - lo) * (255.0 / (hi - lo))
        return np.clip(out, 0, 255).astype(np.uint8)

    @staticmethod
    def _ensure_uint8(image: Array) -> Array:
        if image.dtype == np.uint8:
            return image
        if np.issubdtype(image.dtype, np.floating):
            mx = float(np.nanmax(image)) if image.size else 255.0
            if mx <= 1.0:
                image = image * 255.0
        return np.clip(image, 0, 255).astype(np.uint8)

    @staticmethod
    def _box_blur(image: Array, radius: int) -> Array:
        radius = max(1, int(radius))
        padded = np.pad(image, ((radius, radius), (radius, radius)), mode="reflect")
        integral = padded.cumsum(axis=0).cumsum(axis=1)
        k = 2 * radius + 1
        out = (
            integral[k:, k:]
            - integral[:-k, k:]
            - integral[k:, :-k]
            + integral[:-k, :-k]
        ) / float(k * k)
        return out
