from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable, Tuple

import numpy as np


@dataclass
class RobustFilterResult:
    values: np.ndarray
    mask: np.ndarray
    median: float
    mad: float
    sigma_estimate: float


class RobustStatistics:
    @staticmethod
    def mad(values: Iterable[float]) -> float:
        arr = np.asarray(list(values), dtype=np.float64)
        if arr.size == 0:
            return 0.0
        med = np.median(arr)
        return float(np.median(np.abs(arr - med)))

    @staticmethod
    def robust_sigma(values: Iterable[float]) -> float:
        mad = RobustStatistics.mad(values)
        return float(1.4826 * mad)

    @staticmethod
    def filter_by_mad(values: Iterable[float], threshold: float = 3.5) -> RobustFilterResult:
        arr = np.asarray(list(values), dtype=np.float64)
        if arr.size == 0:
            return RobustFilterResult(arr, np.zeros(0, dtype=bool), 0.0, 0.0, 0.0)
        med = float(np.median(arr))
        mad = float(np.median(np.abs(arr - med)))
        sigma = 1.4826 * mad
        if mad < 1e-12:
            mask = np.ones(arr.shape, dtype=bool)
        else:
            score = np.abs(arr - med) / mad
            mask = score <= threshold
        return RobustFilterResult(arr, mask, med, mad, sigma)

    @staticmethod
    def filter_by_3sigma(values: Iterable[float], mean: float | None = None, sigma: float | None = None) -> np.ndarray:
        arr = np.asarray(list(values), dtype=np.float64)
        if arr.size == 0:
            return np.zeros(0, dtype=bool)
        if mean is None:
            mean = float(np.mean(arr))
        if sigma is None:
            sigma = float(np.std(arr))
        if sigma < 1e-12:
            return np.ones(arr.shape, dtype=bool)
        return np.abs(arr - mean) <= 3.0 * sigma

    @staticmethod
    def iterative_trimmed_mean(values: Iterable[float], max_iters: int = 3) -> Tuple[float, np.ndarray]:
        arr = np.asarray(list(values), dtype=np.float64)
        if arr.size == 0:
            return 0.0, np.zeros(0, dtype=bool)
        mask = np.ones(arr.shape, dtype=bool)
        for _ in range(max_iters):
            cur = arr[mask]
            if cur.size == 0:
                break
            mad_res = RobustStatistics.filter_by_mad(cur, threshold=3.5)
            sigma_mask = RobustStatistics.filter_by_3sigma(cur)
            combined = np.logical_and(mad_res.mask, sigma_mask)
            new_mask = np.zeros_like(mask)
            idx = np.where(mask)[0]
            new_mask[idx[combined]] = True
            if np.array_equal(new_mask, mask):
                break
            mask = new_mask
        if not np.any(mask):
            return float(np.mean(arr)), np.ones(arr.shape, dtype=bool)
        return float(np.mean(arr[mask])), mask

    @staticmethod
    def fit_circle_kasa(points: np.ndarray) -> Tuple[float, float, float]:
        """Algebraic least squares circle fit.

        Args:
            points: Nx2 array of (x, y)
        Returns:
            (cx, cy, r)
        """
        pts = np.asarray(points, dtype=np.float64)
        if pts.ndim != 2 or pts.shape[1] != 2 or len(pts) < 3:
            raise ValueError("Need at least 3 points for circle fitting")

        x = pts[:, 0]
        y = pts[:, 1]
        a = np.column_stack([2 * x, 2 * y, np.ones_like(x)])
        b = x * x + y * y
        sol, *_ = np.linalg.lstsq(a, b, rcond=None)
        cx, cy, c = sol
        r = np.sqrt(max(c + cx * cx + cy * cy, 0.0))
        return float(cx), float(cy), float(r)

    @staticmethod
    def radial_residuals(points: np.ndarray, center: Tuple[float, float], radius: float) -> np.ndarray:
        pts = np.asarray(points, dtype=np.float64)
        d = np.sqrt((pts[:, 0] - center[0]) ** 2 + (pts[:, 1] - center[1]) ** 2)
        return d - float(radius)
